// Sidebar.js
import React from 'react';
import { Link } from 'react-router-dom';
import { FaHome, FaFileAlt, FaChartBar, FaUsers, FaClipboardList, FaSignOutAlt, FaPaw, FaChevronDown, FaChevronUp } from 'react-icons/fa'; // Import thêm icon nếu cần
// import { MdKeyboardArrowDown, MdKeyboardArrowUp } from 'react-icons/md'; // Hoặc các icon khác

function Sidebar() {
  const role = localStorage.getItem('role');

  return (
    <div className="sidebar">
      <h3>📂 QUẢN LÝ LÂM SẢN</h3>
      <ul>
        <li><Link to="/dashboard"><FaHome /> Trang chủ</Link></li>

        {/* Mục Đăng ký và quản lý */}
        <li>
          <details> {/* Bỏ open nếu không muốn mở mặc định */}
            <summary>
              <FaFileAlt /> Đăng ký và quản lý
              {/* Nếu muốn dùng icon riêng cho mũi tên dropdown, thêm vào đây: */}
              {/* <FaChevronDown className="dropdown-icon" /> */}
            </summary>
            <ul>
              <li><Link to="/khai-bao">📝 Khai báo cơ sở nuôi</Link></li>
              {role === 'admin' && (
                <li><Link to="/admin/farms">📋 Quản lý cơ sở nuôi</Link></li>
              )}
            </ul>
          </details>
        </li>

        {/* Mục Thống kê và báo cáo */}
        <li>
          <details>
            <summary>
              <FaChartBar /> Thống kê và báo cáo
              {/* <FaChevronDown className="dropdown-icon" /> */}
            </summary>
            <ul>
              <li><Link to="/dashboard">📈 Thống kê</Link></li>
              <li><Link to="/dashboard">📄 Báo cáo</Link></li>
            </ul>
          </details>
        </li>

        {/* Các mục chỉ dành cho Admin */}
        {role === 'admin' && (
          <>
            <li><Link to="/admin/users"><FaUsers /> Quản lý người dùng</Link></li>
            <li><Link to="/admin/customers"><FaClipboardList /> Quản lý khách hàng</Link></li>
          </>
        )}
        <li><Link to="/logout"><FaSignOutAlt /> Đăng xuất</Link></li>
      </ul>
    </div>
  );
}

export default Sidebar;
